// Approval-Timeout Resilience Framework
// Handles exec approval timeouts gracefully

class ApprovalTimeoutHandler {
  constructor() {
    this.pendingQueue = [];
    this.cache = new Map();
    this.retryDelays = [1000, 5000, 15000, 60000]; // Exponential backoff
  }

  // Attempt to read file with fallback
  async readWithFallback(filePath, options = {}) {
    try {
      // Try direct read first
      const content = await this.tryRead(filePath);
      this.cache.set(filePath, { content, timestamp: Date.now() });
      return { success: true, content, fromCache: false };
    } catch (error) {
      if (this.isApprovalTimeout(error)) {
        // Return cached version if available
        const cached = this.cache.get(filePath);
        if (cached) {
          console.log(`Using cached version of ${filePath} (approval pending)`);
          return { 
            success: true, 
            content: cached.content, 
            fromCache: true,
            cacheAge: Date.now() - cached.timestamp
          };
        }
        // Queue for retry and return graceful degradation
        this.queueForRetry(filePath, options);
        return {
          success: false,
          error: 'approval_timeout',
          message: 'Operation queued for retry when approval is granted',
          queued: true
        };
      }
      throw error;
    }
  }

  // Check if error is approval-related timeout
  isApprovalTimeout(error) {
    const errorStr = error.toString().toLowerCase();
    return errorStr.includes('approval') || 
           errorStr.includes('timeout') || 
           errorStr.includes('rejected');
  }

  // Queue operation for retry with exponential backoff
  queueForRetry(filePath, options) {
    const attempt = options.attempt || 0;
    const delay = this.retryDelays[Math.min(attempt, this.retryDelays.length - 1)];

    this.pendingQueue.push({
      filePath,
      options: { ...options, attempt: attempt + 1 },
      scheduledAt: Date.now() + delay
    });

    console.log(`Queued ${filePath} for retry in ${delay}ms`);
  }

  // Process pending queue
  async processQueue() {
    const now = Date.now();
    const ready = this.pendingQueue.filter(item => item.scheduledAt <= now);

    for (const item of ready) {
      try {
        const result = await this.readWithFallback(item.filePath, item.options);
        if (result.success && !result.fromCache) {
          console.log(`Successfully processed queued item: ${item.filePath}`);
        }
      } catch (error) {
        console.error(`Retry failed for ${item.filePath}:`, error.message);
      }
    }

    // Remove processed items
    this.pendingQueue = this.pendingQueue.filter(item => item.scheduledAt > now);
  }

  // Non-blocking check if file access would require approval
  async canAccessWithoutApproval(filePath) {
    const cached = this.cache.get(filePath);
    if (cached && Date.now() - cached.timestamp < 300000) { // 5 min cache
      return { canAccess: true, fromCache: true };
    }
    return { canAccess: false, fromCache: false };
  }
}

// Usage example
const handler = new ApprovalTimeoutHandler();

// In heartbeat or periodic check
async function checkExplorationProgress() {
  const result = await handler.readWithFallback('exploration/PROGRESS.md');

  if (result.success) {
    if (result.fromCache) {
      console.log('Using cached progress data (approval pending)');
    }
    // Process the content...
    return result.content;
  } else if (result.queued) {
    console.log('Progress check queued for later retry');
    return null;
  }
}

module.exports = { ApprovalTimeoutHandler };
